import React, { useState, useEffect, useRef } from 'react';
import './App.css';

const API_KEY = 'efba491989c2f16eef8e17feba5a0f9b';

function App() {
  const [city, setCity] = useState('');
  const [searchInput, setSearchInput] = useState('');
  const [weather, setWeather] = useState(null);
  const [forecast, setForecast] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [unit, setUnit] = useState('C');

  const abortControllerRef = useRef(null);

  useEffect(() => {
    const lastCity = localStorage.getItem('lastCity');
    if (lastCity) {
      setCity(lastCity);
      setSearchInput(lastCity);
    }
  }, []);

  useEffect(() => {
    if (!city) return;

    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    const fetchData = async () => {
      setLoading(true);
      setError('');
      try {
        const currentResponse = await fetch(
          `https://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${API_KEY}&units=metric`,
          { signal }
        );
        if (!currentResponse.ok) throw new Error('cityNotFound');
        const currentData = await currentResponse.json();

        const forecastResponse = await fetch(
          `https://api.openweathermap.org/data/2.5/forecast?q=${city}&appid=${API_KEY}&units=metric`,
          { signal }
        );
        if (!forecastResponse.ok) throw new Error('cityNotFound');
        const forecastData = await forecastResponse.json();

        setWeather(currentData);
        processForecast(forecastData);
        setLoading(false);
      } catch (err) {
        if (err.name === 'AbortError') return;
        setLoading(false);
        if (err.message === 'cityNotFound') {
          setError('City not found. Please try another city.');
        } else {
          setError('Network error. Please check your connection.');
        }
        setWeather(null);
        setForecast([]);
      }
    };

    fetchData();

    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [city]);

  useEffect(() => {
    if (city) {
      localStorage.setItem('lastCity', city);
    }
  }, [city]);

  const processForecast = (data) => {
    const list = data.list;
    const dailyMap = new Map();

    list.forEach((item) => {
      const date = item.dt_txt.split(' ')[0];
      const temp = item.main.temp;
      const icon = item.weather[0].icon;

      if (!dailyMap.has(date)) {
        dailyMap.set(date, {
          date: date,
          tempMin: temp,
          tempMax: temp,
          icon: icon,
        });
      } else {
        const existing = dailyMap.get(date);
        existing.tempMin = Math.min(existing.tempMin, temp);
        existing.tempMax = Math.max(existing.tempMax, temp);
      }
    });

    const dailyForecast = Array.from(dailyMap.values()).slice(0, 5);
    setForecast(dailyForecast);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (searchInput.trim() === '') return;
    setCity(searchInput.trim());
  };

  const toggleUnit = () => {
    setUnit(unit === 'C' ? 'F' : 'C');
  };

  const convertTemp = (celsius) => {
    if (unit === 'C') return celsius;
    return (celsius * 9/5 + 32).toFixed(1);
  };

  const formatDate = (dateStr) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
  };

  return (
    <div className="app">
      <div className="container">
        <h1>Weather App</h1>
        <form onSubmit={handleSubmit} className="search-form">
          <input
            type="text"
            placeholder="Enter city name..."
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            className="search-input"
          />
          <button type="submit" className="search-btn">Search</button>
        </form>

        <button onClick={toggleUnit} className="unit-toggle">
          Switch to {unit === 'C' ? '°F' : '°C'}
        </button>

        {loading && (
          <div className="spinner-container">
            <div className="spinner"></div>
          </div>
        )}

        {error && <div className="error-message">{error}</div>}

        {!loading && !error && weather && (
          <div className="weather-card">
            <div className="weather-header">
              <h2>{weather.name}</h2>
              <img
                src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@2x.png`}
                alt={weather.weather[0].description}
              />
            </div>
            <div className="weather-temp">
              {convertTemp(weather.main.temp)}°{unit}
            </div>
            <div className="weather-details">
              <p>Condition: {weather.weather[0].main}</p>
              <p>Humidity: {weather.main.humidity}%</p>
              <p>Wind Speed: {weather.wind.speed} m/s</p>
            </div>
          </div>
        )}

        {!loading && !error && forecast.length > 0 && (
          <div className="forecast-section">
            <h3>5-Day Forecast</h3>
            <div className="forecast-grid">
              {forecast.map((day, idx) => (
                <div key={idx} className="forecast-card">
                  <div className="forecast-date">{formatDate(day.date)}</div>
                  <img
                    src={`https://openweathermap.org/img/wn/${day.icon}.png`}
                    alt="forecast icon"
                  />
                  <div className="forecast-temps">
                    <span className="high">{convertTemp(day.tempMax)}°{unit}</span>
                    <span className="low">{convertTemp(day.tempMin)}°{unit}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
